import{_ as t,o,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"60. Community Workload Management System Cwms","description":"","frontmatter":{"title":"60. Community Workload Management System Cwms","eba":"Mental Health Services 2024-2028","topics":["preliminary","staffing"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/60-community-workload-management-system-cwms.md","filePath":"ebas/mental-health/common-terms/staffing/60-community-workload-management-system-cwms.md"}'),a={name:"ebas/mental-health/common-terms/staffing/60-community-workload-management-system-cwms.md"};function r(s,e,l,p,c,m){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_60-community-workload-management-system-cwms" tabindex="-1">60. Community Workload Management System Cwms <a class="header-anchor" href="#_60-community-workload-management-system-cwms" aria-label="Permalink to &quot;60. Community Workload Management System Cwms&quot;">​</a></h1><p><strong>60.1</strong> Each Employer to operate and maintain a CWMS</p><p><strong>(a)</strong> A Community Workload Management System (CWMS) agreed between the Employer and Unions is to be operated and maintained by each Employer via the local Mental Health Workplace Implementation Committee (MHWIC).</p><p><strong>(b)</strong> The CWMS must operate in accordance with the CWMS principles at subclause 60.3.</p><p><strong>(c)</strong> The parties will cooperate through the MHICC to replace the existing CWMS referred to at 60.1(a) with a generic electronic CWMS system as soon as practicable and no later than the end of 2027.</p><p><strong>60.2</strong> Reporting Requirements The parties to the Agreement are committed to embedding an effective CWMS system. The parties understand this requires collaboration and co-operation between the parties.</p><p><strong>(a)</strong> In order to assist this process, the Employer will:</p><p><strong>(i)</strong> develop a reporting template, in consultation with the Unions, to record data for each relevant community team; and</p><p><strong>(ii)</strong> provide this data quarterly to the parties via the local and central MHIIC.</p><p><strong>(b)</strong> Where the data shows that the CWMS principles have not been met, the parties will:</p><p><strong>(i)</strong> seek to identify the reason(s); and</p><p><strong>(ii)</strong> discuss the actions that have been taken or are proposed to be taken to address this,</p><p><strong>(c)</strong> Where, after the steps outlined in 60.2(b), a member of the local MHIIC is not satisfied that actions are sufficient to satisfy the CWMS principles, the local MHIIC will genuinely attempt to resolve concerns through discussion.</p><p><strong>(d)</strong> No party to the local MHICC or person covered by the Agreement will be prejudiced as a result of either the provision of data or the discussions under this sub-clause 60.2 or initiate a dispute where 60.2(c) is being complied with.</p><p><strong>(e)</strong> For the avoidance of doubt, clause 60.2 does not prevent an Employee or their representative enforcing their rights in accordance with clause 60.8.</p><p><strong>60.3</strong> CWMS Principles</p><p><strong>(a)</strong> The CWMS is required to apply the following in respect of each community clinician:</p><p><strong>(i)</strong> Direct clinical commitments time of up to 60% of working hours inclusive of a secondary caseload allocation; and</p><p><strong>(ii)</strong> Organisational time and practitioner development time of not less than 40% of working hours)</p><p><strong>(b)</strong> All tasks assigned to an Employee, including caseload allocation and fixed and variable clinical and organisational commitments, must be capable of being completed within the Employee&#39;s normal ordinary weekly or fortnightly hours of duty.</p><p><strong>60.4</strong> Exceptions to clauses 60.3(a)</p><p><strong>(a)</strong> Clinicians in a Community Mental Health Team in training positions, graduate positions, project positions or newly appointed staff on designated orientation periods will have direct clinical commitment hours of less than 60 % for a time limited period as part of their position work plan arrangements, and in line with their skill level and /or orientation needs.</p><p><strong>(b)</strong> Supervisors/team leaders/senior clinicians in a Community Mental Health Team will have Organisational and Practitioner Development hours allocated to reflect any additional supervisory/management duties required to be undertaken.</p><p><strong>60.5</strong> Status Quo for an Employer at 40% or above Services that have organisational and practitioner development allocation (as per clause</p><p><strong>60.3</strong> above) at 40% or above must maintain the status quo.</p><p><strong>60.6</strong> Variation The CWMS Principles at clause 60.3(a) may be varied by agreement between the Unions and the Employer to deal with peculiar, localised need where evidenced. This will be recorded in writing as a local agreement signed by the parties.</p><p><strong>60.7</strong> Definitions</p><p><strong>(a)</strong> Agreed means agreed between the Employer and Unions via the local MHWIC.</p><p><strong>(b)</strong> Overarching principles are those contained at 9.6.3(e) of the January 2011 publication ‘Victorian Public Mental Health Caseload Management Standard 2011’. Column A Column B No. Direct clinical commitments Organisational and Practitioner Development commitments 1 Client contact and/or engagement with families or Handover carers and/or nominated persons (includes Registered Contacts); this includes patients or clients previously registered with the mental health service 2 Unregistered client contact such as when services Rostered duty time are provided to people who are not registered with the local area mental health service. 3 Community centred contact occurs when a Staff/team meetings service is provided by the mental health service to a community organisation or service provider working in a non-mental health specific setting. This includes, but is not limited to, the following:</p><p><strong>(a)</strong> Consultation services</p><p><strong>(b)</strong> Case conferences</p><p><strong>(c)</strong> Community Education and social activities</p><p><strong>(d)</strong> Community Development activities 4 Clinically related administrative work (e.g. Rest breaks Reading, researching or reviewing any patient’s documentation for any purpose) 5 Other clinical direct care duties required by the Clinical Review team Meeting(s) 6 Travel time ADO (full-time Employees) 7 Intra-agency liaison meetings and training CWMS reviews time (between Employee and Manager). Time to meet/complete CWMT. 8 Individual Clinician triage and allocation Supervision of students (if applicable) 9 Review and Discharge Portfolios, however titled (if applicable) 10 Discipline specific responsibilities Clinical supervision</p><p>Column A Column B Time for documentation requirements, such as, Staff/Professional but not limited to: Development</p><p><strong>(a)</strong> Progress notes and clinical documentation</p><p><strong>(b)</strong> Clinical review preparations</p><p><strong>(c)</strong> Outcome measures</p><p><strong>(d)</strong> Reports</p><p><strong>(e)</strong> Risk assessments</p><p><strong>(f)</strong> Statistics Secondary caseload</p><p><strong>60.8</strong> Non-compliance</p><p><strong>(a)</strong> In the event an Employee’s workload is not compliant with this clause, the Employer will take immediate steps to adjust the Employee’s workload to ensure compliance.</p><p><strong>(b)</strong> From the commencement of this Agreement, where the Employees’ workload remains non-compliant within two months after the completion of the monthly reporting period, the Employer will take the following immediate steps:</p><p><strong>(i)</strong> the Employee will be rostered 1 clear day free from direct clinical care (non-direct clinical time) during the next reporting period; and</p><p><strong>(ii)</strong> the Employee will not be allocated any additional cases that will increase Column A activity until such time the Employee’s workload meets the 60/40 threshold.</p><p><strong>(c)</strong> The period of time referred to in 60.8(a) will reduce to one month following the end of the reporting period once the electronic reporting tool referred to in 60.1(c) is implemented.</p><p><strong>(d)</strong> Subclause 60.8(b) will not apply where:</p><p><strong>(i)</strong> the Employee does not complete the tool.</p><p><strong>(ii)</strong> the Employee has been on periods of absence that distort the reporting results.</p><p><strong>(iii)</strong> the MHICC through consensus provides an exemption to the obligation at 60.8(b)(ii) to a specific area in writing for a prescribed period of time.</p><p><strong>(e)</strong> Workload will be assessed at the same point each month.</p><p><strong>60.9</strong> Overtime Overtime and/or time in lieu should not be used as a means to augment the existing workforce or workload requirements.</p><p><strong>60.10</strong> Secondary caseloads</p><p><strong>(a)</strong> In determining how to manage the caseload of a clinician during periods of planned and unplanned absences, consideration will be given at team level to the following:</p><p><strong>(i)</strong> other clinician&#39;s caseload commitments</p><p><strong>(ii)</strong> the principle that a clinician&#39;s caseload capacity and case management (including secondary caseload capacity) is determined by the CWMS and requirements referred to in this clause.</p><p><strong>(b)</strong> Where the full or partial secondary caseload is agreed to be absorbed within the team the cases will be appropriately allocated according to the above principles and will comply with the CWMS principles</p><p><strong>(c)</strong> Backfill will be provided if the secondary caseload is unable to be managed despite active prioritisation of caseload at team level.</p><p><strong>60.11</strong> No Disadvantage No clinician will be subject to less favourable treatment by the Employer by reason of the Employee seeking to enforce their rights under this clause.</p><p><strong>60.12</strong> Application of the Dispute Clause</p><p><strong>60.13</strong> The Disputes clause of this Agreement applies to this clause, including whether a review is warranted for a particular Employer and in respect of sub-clause 60.8.</p>',61)])])}const h=t(a,[["render",r]]);export{g as __pageData,h as default};
